INSERT INTO 表名 (lang, lb_id, difficulty, page, title, tags, summary, content, eg_in, eg_out) VALUES
('cpp', 16, 'beginner', 1, '使用 cout 进行输出', '["输出","cout","endl"]', '介绍使用 cout 进行控制台输出的基本语法。', 'std::cout 是 C++ 标准库中用于向标准输出流（通常是控制台）发送数据的对象。它定义在 <iostream> 头文件中。使用插入运算符 << 可以将数据发送到 cout。endl 操作符用于插入换行并刷新输出缓冲区。', '["#include <iostream>\nusing namespace std;\n\nint main() {\n    cout << \"Hello, World!\" << endl;\n    return 0;\n}"]', '["Hello, World!"]'),
('cpp', 17, 'beginner', 1, '使用 cin 进行输入', '["输入","cin"]', '介绍使用 cin 从控制台读取用户输入的基本语法。', 'std::cin 是 C++ 标准库中用于从标准输入流（通常是键盘）读取数据的对象。它同样定义在 <iostream> 头文件中。使用提取运算符 >> 可以将数据从 cin 提取到变量中。运算符 >> 会跳过空白字符（如空格、制表符、换行符），并等待用户输入。', '["#include <iostream>\nusing namespace std;\n\nint main() {\n    int age;\n    cout << \"Enter your age: \";\n    cin >> age;\n    cout << \"Your age is: \" << age << endl;\n    return 0;\n}"]', '["Enter your age: 25\nYour age is: 25"]'),
('cpp', 18, 'beginner', 1, 'cin 与 cout 的简单组合使用', '["输入","输出","cin","cout"]', '展示如何结合使用 cin 和 cout 实现简单的交互程序。', '一个典型的交互式程序会使用 cout 提示用户，然后使用 cin 读取用户的输入，最后再用 cout 输出处理后的结果。这是构建控制台程序的基础。', '["#include <iostream>\nusing namespace std;\n\nint main() {\n    string name;\n    int year;\n    cout << \"Enter your name: \";\n    cin >> name;\n    cout << \"Enter your birth year: \";\n    cin >> year;\n    int age = 2023 - year; // 示例年份\n    cout << \"Hello, \" << name << \"! You are about \" << age << \" years old.\" << endl;\n    return 0;\n}"]', '["Enter your name: Alice\nEnter your birth year: 1998\nHello, Alice! You are about 25 years old."]'),
('cpp', 19, 'beginner', 1, '格式化输出（setw, setprecision）', '["输出","格式化","iomanip"]', '介绍如何使用 <iomanip> 头文件中的操作符进行简单的格式化输出。', '<iomanip> 头文件提供了一些用于控制输出格式的操作符。std::setw(n) 设置下一个输出字段的宽度为 n 个字符。std::setprecision(n) 设置浮点数的精度（显示的有效数字位数或小数点后的位数，取决于输出模式）。通常与 std::fixed 结合使用来固定小数点后的位数。', '["#include <iostream>\n#include <iomanip>\nusing namespace std;\n\nint main() {\n    double pi = 3.1415926535;\n    cout << \"Default: \" << pi << endl;\n    cout << \"Fixed with precision 2: \" << fixed << setprecision(2) << pi << endl;\n    cout << \"Width 10, precision 3: |\" << setw(10) << setprecision(3) << pi << \"|\" << endl;\n    int num = 42;\n    cout << \"Number with width 5: |\" << setw(5) << num << \"|\" << endl;\n    return 0;\n}"]', '["Default: 3.14159\nFixed with precision 2: 3.14\nWidth 10, precision 3: |     3.142|\nNumber with width 5: |   42|"]'),
('cpp', 20, 'beginner', 1, '使用 getline 读取整行字符串', '["输入","字符串","getline"]', '介绍如何使用 getline 函数读取包含空格的整行输入。', '使用 cin >> variable 读取字符串时，会在遇到空白字符（空格、制表符）时停止。为了读取一整行文本（包括其中的空格），可以使用 std::getline(std::cin, string_variable) 函数。它从输入中读取字符，直到遇到换行符，并将结果（不包含换行符）存储到字符串变量中。注意：在使用 getline 之前，如果前面有用 >> 读取过数据，可能需要使用 cin.ignore() 来清除输入缓冲区中残留的换行符。', '["#include <iostream>\n#include <string>\nusing namespace std;\n\nint main() {\n    string fullName;\n    cout << \"Enter your full name: \";\n    getline(cin, fullName); // 读取整行\n    cout << \"Hello, \" << fullName << \"!\" << endl;\n\n    // 混合输入示例：先读数字，再读整行字符串\n    int id;\n    string department;\n    cout << \"\\nEnter your ID: \";\n    cin >> id;\n    cin.ignore(); // 忽略数字后的换行符\n    cout << \"Enter your department: \";\n    getline(cin, department);\n    cout << \"ID: \" << id << \", Department: \" << department << endl;\n    return 0;\n}"]', '["Enter your full name: John Doe\nHello, John Doe!\n\nEnter your ID: 1001\nEnter your department: Computer Science\nID: 1001, Department: Computer Science"]');